    const badgeBaseClass = "flex items-center justify-center gap-2 px-3 h-7 rounded-full border shadow-sm backdrop-blur-md transition-all duration-300";
    const textBaseClass = "text-[10px] font-black uppercase tracking-widest leading-none pt-px";

    // --- HELPER: GET MODEL NAME ---
    const activeModelName = useMemo(() => {
        if (!activeKeyProfile) return "OFFLINE";
        const m = (activeKeyProfile.activeModel || "").toLowerCase();

        // Concise & Succinct Mappings
        if (m.includes("3-pro")) return "3.0 PRO";
        if (m.includes("3-flash")) return "3.0 FLASH";

        if (m.includes("lite")) return "2.0 LITE";
        if (m.includes("2.0-flash")) return "2.0 FLASH";
        if (m.includes("exp")) return "2.0 EXP"; 

        if (m.includes("1.5-pro")) return "1.5 PRO";
        if (m.includes("1.5-flash")) return "1.5 FLASH";

        // Smart Fallback for unknown models
        // Tries to extract version number (e.g. 1.0) and type (pro/ultra)
        const versionMatch = m.match(/(\d+\.\d+)/);
        const version = versionMatch ? versionMatch[0] : "";

        if (m.includes("ultra")) return `${version} ULTRA`;
        if (m.includes("nano")) return `${version} NANO`;
        if (version) return `GEMINI ${version}`;

        return "GEMINI AI";
    }, [activeKeyProfile]);

    // --- AI STATUS CONFIG ---
    const aiStatusConfig = useMemo(() => {
        if (!activeKeyProfile) return { 
            status: "offline",
            dotColor: "bg-slate-300 dark:bg-slate-600",
