export const generateAuditSchedule = async (
    sites: AuditSite[],
    team: AuditMember[],
    processes: AuditProcess[],
    config: AuditPlanConfig,
    apiKey?: string,
    model?: string,
    leadAuditorInfo?: { name: string, code?: string }
) => {
    const ai = getAiClient(apiKey);
    if (!ai) throw new Error("API Key missing");

    // --- LOGIC 1: LEAD AUDITOR HANDLING ---
    // If team is empty, force create Lead Auditor from Sidebar info.
    // If team exists, use it AS IS (do not auto-add lead to prevent duplicates/unwanted entries).
    let finalTeam = [...team];

    if (finalTeam.length === 0 && leadAuditorInfo?.name) {
        finalTeam.push({
            id: 'lead_auto',
            name: leadAuditorInfo.name,
            role: 'Lead Auditor',
            competencyCodes: leadAuditorInfo.code || "", 
            manDays: 1,
            isRemote: false,
            availability: "Full Time"
        });
    }

    // --- LOGIC 3: COMPACT CSV DATA ---
    const sitesCompact = sites.map(s => `${s.id},${s.name},${s.isMain?'HQ':'Site'}`).join("\n");

    const teamCompact = finalTeam.map(m => 
        `${m.name},${m.role},${m.competencyCodes||'ALL'},${m.isRemote?'R':'O'}`
    ).join("\n");

    const processReqs = processes.map(p => {
        const siteConstraint = p.siteIds && p.siteIds.length > 0 ? p.siteIds.join(';') : "ALL";
        // Pass FULL List of clauses to allow AI to group them
        const clauses = Object.keys(p.matrixData).join(";");
        return `${p.name},${p.competencyCode || "NONE"},${siteConstraint},[${clauses}]`;
    }).join("\n");

    const datesList = config.auditDates.join(", ");

    // --- LOGIC 2: MANDATORY EVENTS & GROUPING (Injected via Template update or here) ---
    // We append the specific constraints here to ensure they override generic template rules
    const mandatoryEvents = `
    CRITICAL PLANNING RULES:
    1. **Opening Meeting**: Must be the FIRST activity on Day 1 (08:30-09:00).
    2. **Closing Meeting**: Must be the LAST activity on the Last Day (16:00-17:00).
    3. **Interim Briefing**: Must be scheduled at the end of every day (except the last day).
    4. **Activity Grouping**: DO NOT list every clause as a separate row. Group related clauses into logical activities (e.g., "Incident Management" for 5.24-5.29, "Business Continuity" for 5.30+). 
       - In 'activity', write the group name.
       - In 'clauseRefs', list ALL covered clause numbers. 
       - Ensure 100% coverage of input clauses.
    `;

    const template = PromptRegistry.getPrompt('SCHEDULING');

    let baseTemplate = template.template.replace('{{SITES_COMPACT}}', `[ID,Name,Type]\n${sitesCompact}`)
                                        .replace('{{TEAM_COMPACT}}', `[Name,Role,Codes,Remote]\n${teamCompact}`)
                                        .replace('{{PROCESS_REQUIREMENTS}}', `[Name,ReqCode,SiteIDs,Clauses]\n${processReqs}`);

    // Inject mandatory rules
    baseTemplate = baseTemplate.replace('PARAMS:', `${mandatoryEvents}\n\nPARAMS:`);

    if (!baseTemplate.includes("VALID_AUDITORS")) {
        baseTemplate += `\n\nRULES:\n1. Match Process.ReqCode to Auditor.Codes.\n2. Balance workload across ${datesList}.\n3. Output JSON.`;
    }

    const prompt = PromptRegistry.hydrate(baseTemplate, {
        START_TIME: config.startTime,
        END_TIME: config.endTime,
        LUNCH_START: config.lunchStartTime,
        LUNCH_END: config.lunchEndTime,
        DATES: datesList,
        SITES_COMPACT: "", // Handled above
        TEAM_COMPACT: "", // Handled above
        PROCESS_REQUIREMENTS: "" // Handled above
    });

    const configGen: any = {
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    day: { type: Type.INTEGER },
                    date: { type: Type.STRING },
                    timeSlot: { type: Type.STRING },
                    activity: { type: Type.STRING },
                    siteName: { type: Type.STRING },
                    auditorName: { type: Type.STRING },
                    processName: { type: Type.STRING },
                    clauseRefs: { type: Type.ARRAY, items: { type: Type.STRING } },
                    isRemote: { type: Type.BOOLEAN }
                },
                required: ["day", "date", "timeSlot", "activity", "auditorName", "processName"]
            }
        }
    };

    try {
        return await executeWithModelCascade(
            model || "gemini-3-pro-preview", 
            "Audit Schedule",
            (m) => ai.models.generateContent({
                model: m,
                contents: prompt,
                config: configGen
            })
        );
    } catch (e) {
        console.error("Schedule Gen Failed", e);
        throw e;
    }
};

