                                                    <div className={`flex-1 relative z-10 flex items-center justify-center gap-1.5 transition-colors duration-300 ${!newMember.isRemote ? 'text-indigo-600 dark:text-indigo-300' : 'text-slate-500 dark:text-slate-500'}`}>
