                                                {/* SMART TEMPLATE ADAPTER BUTTON */}
                                                <div className="relative group">
                                                    <input 
                                                        type="file" 
                                                        ref={fileTemplateRef}
                                                        accept="image/*" 
                                                        className="hidden" 
                                                        onChange={handleTemplateUpload} 
